using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    public void TakeDamage(int damage)
    {
        health -= damage;
        if (health < 0) health = 0;
    }

    public void AddCurrency(int amount)
    {
        currency += amount;
    }

    public bool PurchaseItem(int itemPrice)
    {
        if (currency >= itemPrice)
        {
            currency -= itemPrice;
            return true;
        }
        return false;
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats playerStats;

    public void BuyHealthPotion()
    {
        int potionPrice = 20;
        if (playerStats.PurchaseItem(potionPrice))
        {
            playerStats.health += 20;
            if (playerStats.health > 100) playerStats.health = 100;
        }
    }

    public void BuyCurrency(int amount)
    {
        int pricePerUnit = 1;
        int totalPrice = amount * pricePerUnit;
        if (playerStats.PurchaseItem(totalPrice))
        {
            playerStats.currency += amount;
        }
    }
}

public class GameManager : MonoBehaviour
{
    public PlayerStats playerStats;

    void Start()
    {
        playerStats = new PlayerStats();
        playerStats.AddCurrency(50); // Initial currency for testing
    }

    void Update()
    {
        if (Input.GetKeyDown(KeyCode.Space)) // Simulate taking damage
        {
            playerStats.TakeDamage(10);
        }

        if (Input.GetKeyDown(KeyCode.B)) // Simulate buying a health potion
        {
            Shop shop = new Shop();
            shop.playerStats = playerStats;
            shop.BuyHealthPotion();
        }
    }
}